<template>
	<view class="page-container">
		<!-- жҗңзҙўжЎҶ -->
		<view class="search-box">
			<text class="search-label">ж—Ҙжңҹжҗңзҙў</text>
			<input 
				class="search-input" 
				name="date" 
				v-model="search.date" 
				placeholder="иҜ·иҫ“е…Ҙж—Ҙжңҹ"
				@blur="getList"
			/>
		</view>
		
		<!-- еҲ—иЎЁ -->
		<view class="list-section">
			<view 
				class="list-item" 
				v-for="(item,i) in list" 
				:key="i" 
				@click="editInfo(item)"
			>
				<text class="item-date">{{item.date}}</text>
				<text class="item-title">{{item.title}}</text>
				<text class="item-arrow">вҖә</text>
			</view>
			
			<view v-if="!list.length" class="empty-list">
				<text>жҡӮж— ж•°жҚ®</text>
			</view>
		</view>
		
		<!-- иЎЁеҚ• -->
		<view class="form-section">
			<form>
				<view class="form-item">
					<text class="form-label">ж—Ҙжңҹ</text>
					<input 
						class="form-input" 
						name="date" 
						v-model="formData.date" 
						placeholder="иҜ·иҫ“е…Ҙж—ҘжңҹпјҲеҰӮпјҡ2024-1-1пјү"
					/>
				</view>
				
				<view class="form-item">
					<text class="form-label">ж Үйўҳ</text>
					<input 
						class="form-input" 
						name="title" 
						v-model="formData.title" 
						placeholder="иҜ·иҫ“е…Ҙж Үйўҳ"
					/>
				</view>
				
				<view class="form-item">
					<text class="form-label">еӨҮжіЁ</text>
					<textarea 
						class="form-textarea" 
						name="bz" 
						v-model="formData.bz" 
						placeholder="иҜ·иҫ“е…ҘеӨҮжіЁ"
					/>
				</view>
				<view class="form-item">
					<text class="form-label">зұ»еһӢ</text>
					<input 
						class="form-input" 
						name="title" 
						v-model="formData.type" 
						placeholder="1йҮҚиҰҒпјҢ2зі–"
					/>
				</view>
				
				<view class="form-item">
					<text class="form-label">еӣҫзүҮи·Ҝеҫ„</text>
					<textarea 
						class="form-textarea" 
						name="imgurl" 
						v-model="formData.imgurl" 
						placeholder="иҜ·иҫ“е…ҘеӣҫзүҮи·Ҝеҫ„пјҢеӨҡдёӘз”ЁеҲҶеҸ·йҡ”ејҖ"
					/>
				</view>
				
				<view class="form-actions" v-if="formData._id">
					<button 
						type="primary" 
						class="action-btn update-btn" 
						@click="submit('update')"
					>
						жӣҙж–°
					</button>
					<button 
						type="primary" 
						class="action-btn delete-btn" 
						@click="remove(formData._id)"
						v-if=" isCalendarPermission('del') "
					>
						еҲ йҷӨ
					</button>
					<button 
						type="primary" 
						class="action-btn clear-btn" 
						@click="clearForm"
					>
						жё…з©ә
					</button>
				</view>
				
				<button 
					type="primary" 
					class="action-btn save-btn full-width" 
					@click="submit('add')" 
					v-else
				>
					дҝқеӯҳ
				</button>
			</form>
		</view>
		
		<!-- й—®еҖҷиҜӯи®ҫзҪ® -->
		<view class="greeting-section">
			<view class="section-title">
				<text class="title-icon">рҹ””</text>
				<text>й—®еҖҷиҜӯи®ҫзҪ®</text>
			</view>
			<form>
				<view class="form-item">
					<text class="form-label">й—®еҖҷиҜӯ</text>
					<input 
						class="form-input" 
						name="greeting" 
						v-model="customGreeting.title" 
						placeholder="иҜ·иҫ“е…Ҙй—®еҖҷиҜӯ"
					/>
				</view>
				
				<button 
					type="primary" 
					class="action-btn save-btn full-width" 
					@click="add_customGreeting"
				>
					дҝқеӯҳй—®еҖҷиҜӯ
				</button>
			</form>
		</view>
	</view>
</template>

<script>
import { hasCalendarPermission } from '@/common/js/permission.js'
	export default{
		data(){
			return{
				list:[],
				formData:{
					title:'',
					bz:'',
					date:'',
					imgurl:'',
					type:''
				},
				search:{
					date:''
				},
				customGreeting:{
					title:''
				},
				userInfo:null
			}
		},
		onLoad() {
			const userInfo = uni.getStorageSync('userInfo');
				this.userInfo=JSON.parse(userInfo)
		},
		methods:{
			isCalendarPermission(type) {
				return hasCalendarPermission(this.userInfo, type)
			},
			editInfo(item){
				this.formData= {...item};
			},
			add_customGreeting(){
				if(!this.customGreeting.title&&!this.customGreeting.bgcolor){
					uni.showModal({
						content: `иҜ·иҫ“е…Ҙжңүж•Ҳж•°жҚ®`,
						showCancel: false
					})
					return
					
				}
				uni.showLoading({
					title: 'еӨ„зҗҶдёӯ...'
				})
				uniCloud.callFunction({
					name: 'welcome',
					data: {
						type:'update',
						params:this.customGreeting,
					}
				}).then((res) => {
					uni.hideLoading()
					uni.showModal({
						content: `й—®еҖҷиҜӯдҝ®ж”№жҲҗеҠҹ`,
						showCancel: false
					})
					this.clearForm()
				}).catch((err) => {
					uni.hideLoading()
					uni.showModal({
						content: `дҝ®ж”№ж•°жҚ®еӨұиҙҘ`,
						showCancel: false
					})
					console.error(err)
				})
			},
			add() {
				uni.showLoading({
					title: 'еӨ„зҗҶдёӯ...'
				})
				uniCloud.callFunction({
					name: 'rili-add',
					data: {
						type:'add',
						params:this.formData
					}
				}).then((res) => {
					uni.hideLoading()
					uni.showModal({
						content: `жҲҗеҠҹж·»еҠ дёҖжқЎж•°жҚ®пјҢж–ҮжЎЈidдёәпјҡ${res.result.id}`,
						showCancel: false
					})
					this.clearForm()
				}).catch((err) => {
					uni.hideLoading()
					uni.showModal({
						content: `ж·»еҠ ж•°жҚ®еӨұиҙҘпјҢй”ҷиҜҜдҝЎжҒҜдёәпјҡ${err.message}`,
						showCancel: false
					})
					console.error(err)
				})
			},
			remove(id) {
				uni.showLoading({
					title: 'еӨ„зҗҶдёӯ...'
				})
				uniCloud.callFunction({
					name: 'rili-add',
					data: {
						type:'del',
						params:this.formData._id
					}
				}).then((res) => {
					uni.hideLoading()
					uni.showModal({
						content: `еҲ йҷӨжҲҗеҠҹ`,
						showCancel: false
					})
					this.getList()
					//console.log(res)
				}).catch((err) => {
					uni.hideLoading()
					uni.showModal({
						content: `еҲ йҷӨеӨұиҙҘпјҢй”ҷиҜҜдҝЎжҒҜдёәпјҡ${err.message}`,
						showCancel: false
					})
					console.error(err)
				})
			},
			update() {
				uni.showLoading({
					title: 'еӨ„зҗҶдёӯ...'
				})
				uniCloud.callFunction({
					name: 'rili-add',
					data: {
						type:'update',
						params:this.formData
					}
				}).then((res) => {
					uni.hideLoading()
					uni.showModal({
						content: `жӣҙж–°жҲҗеҠҹ`,
						showCancel: false
					})
					this.getList()
					//console.log(res)
				}).catch((err) => {
					uni.hideLoading()
					uni.showModal({
						content: `жӣҙж–°ж“ҚдҪңжү§иЎҢеӨұиҙҘпјҢй”ҷиҜҜдҝЎжҒҜдёәпјҡ${err.message}`,
						showCancel: false
					})
					console.error(err)
				})
			},
			submit(type) {
				if(type==='add'){
					this.add()
				}else if(type==='update'){
					this.update()
				}
			},
			getList() {
				
				uni.showLoading({
					title: 'еӨ„зҗҶдёӯ...'
				})
				uniCloud.callFunction({
					name: 'rili-get',
					data:{
						search:this.search
					}
				}).then((res) => {
					uni.hideLoading()
					
					this.list=res.result.data ||[]
				}).catch((err) => {
					uni.hideLoading()
					uni.showModal({
						content: `жҹҘиҜўеӨұиҙҘпјҢй”ҷиҜҜдҝЎжҒҜдёәпјҡ${err.message}`,
						showCancel: false
					})
					console.error(err)
				})
			},
			clearForm(){
				this.formData._id=''
				this.formData.date=''
				this.formData.title=''
				this.formData.bz=''
				this.formData.imgurl=''
				
			}
		}
	}
</script>

<style lang="scss">
// йЎөйқўе®№еҷЁ
.page-container {
	min-height: 100vh;
	background: linear-gradient(180deg, #cff8f5 0%, #e6cffc 100%);
	padding: 16px;
}

// жҗңзҙўжЎҶ
.search-box {
	background: #fff;
	border-radius: 12px;
	padding: 12px 16px;
	margin-bottom: 16px;
	box-shadow: 0 2px 8px rgba(0, 0, 0, 0.06);
	display: flex;
	align-items: center;
	
	.search-label {
		font-size: 14px;
		color: #666;
		margin-right: 12px;
		white-space: nowrap;
	}
	
	.search-input {
		flex: 1;
		font-size: 15px;
	}
}

// еҲ—иЎЁеҢәеҹҹ
.list-section {
	background: #fff;
	border-radius: 12px;
	padding: 8px;
	margin-bottom: 16px;
	box-shadow: 0 2px 8px rgba(0, 0, 0, 0.06);
	
	.list-item {
		display: flex;
		align-items: center;
		padding: 14px 16px;
		border-radius: 8px;
		margin-bottom: 4px;
		background: #fafafa;
		transition: all 0.3s ease;
		
		&:last-child {
			margin-bottom: 0;
		}
		
		&:active {
			background: #f0f0f0;
		}
		
		.item-date {
			font-size: 13px;
			color: #aaa1ce;
			margin-right: 12px;
			white-space: nowrap;
		}
		
		.item-title {
			flex: 1;
			font-size: 15px;
			color: #333;
			overflow: hidden;
			text-overflow: ellipsis;
			white-space: nowrap;
		}
		
		.item-arrow {
			font-size: 20px;
			color: #999;
			margin-left: 8px;
		}
	}
	
	.empty-list {
		text-align: center;
		padding: 30px;
		color: #999;
		font-size: 14px;
	}
}

// иЎЁеҚ•еҢәеҹҹ
.form-section {
	background: #fff;
	border-radius: 12px;
	padding: 16px;
	margin-bottom: 16px;
	box-shadow: 0 2px 8px rgba(0, 0, 0, 0.06);
	
	.form-item {
		margin-bottom: 16px;
		
		&:last-child {
			margin-bottom: 0;
		}
		
		.form-label {
			display: block;
			font-size: 14px;
			color: #666;
			margin-bottom: 8px;
			font-weight: 500;
		}
		
		.form-input {
			width: 100%;
			height: 44px;
			background: #f5f7fa;
			border-radius: 8px;
			padding: 0 12px;
			font-size: 15px;
		}
		
		.form-textarea {
			width: 100%;
			min-height: 80px;
			background: #f5f7fa;
			border-radius: 8px;
			padding: 12px;
			font-size: 15px;
			line-height: 1.5;
		}
	}
	
	.form-actions {
		display: flex;
		gap: 12px;
		margin-top: 24px;
		
		.action-btn {
			flex: 1;
			height: 44px;
			line-height: 44px;
			border-radius: 8px;
			font-size: 15px;
			font-weight: 500;
			border: none;
		}
		
		.save-btn {
			background: linear-gradient(135deg, #aaa1ce 0%, #9b8fbf 100%);
			color: #fff;
		}
		
		.update-btn {
			background: linear-gradient(135deg, #4facfe 0%, #00f2fe 100%);
			color: #fff;
		}
		
		.delete-btn {
			background: linear-gradient(135deg, #fa709a 0%, #fee140 100%);
			color: #fff;
		}
		
		.clear-btn {
			background: linear-gradient(135deg, #ffecd2 0%, #fcb69f 100%);
			color: #333;
		}
		
		.full-width {
			width: 100%;
		}
	}
}

// й—®еҖҷиҜӯи®ҫзҪ®еҢәеҹҹ
.greeting-section {
	background: #fff;
	border-radius: 12px;
	padding: 16px;
	box-shadow: 0 2px 8px rgba(0, 0, 0, 0.06);
	
	.section-title {
		display: flex;
		align-items: center;
		margin-bottom: 16px;
		padding-bottom: 12px;
		border-bottom: 1px solid #f0f0f0;
		
		.title-icon {
			width: 20px;
			height: 20px;
			margin-right: 8px;
		}
		
		text {
			font-size: 16px;
			font-weight: 600;
			color: #333;
		}
	}
	
	.form-item {
		margin-bottom: 16px;
		
		.form-label {
			display: block;
			font-size: 14px;
			color: #666;
			margin-bottom: 8px;
			font-weight: 500;
		}
		
		.form-input {
			width: 100%;
			height: 44px;
			background: #f5f7fa;
			border-radius: 8px;
			padding: 0 12px;
			font-size: 15px;
		}
	}
	
	.action-btn {
		width: 100%;
		height: 44px;
		line-height: 44px;
		border-radius: 8px;
		font-size: 15px;
		font-weight: 500;
		border: none;
		background: linear-gradient(135deg, #aaa1ce 0%, #9b8fbf 100%);
		color: #fff;
	}
}

// дҝқз•ҷж—§ж ·ејҸ
.flex-row {
	display: flex;
}

.title {
	color: cadetblue;
}

.page {
	padding: 5px;
}

.uni-form-item {
	margin-bottom: 10px;
}

.search-box {
	background: #eee;
	margin-bottom: 15px;
	padding: 3px;
}

.list {
	margin-bottom: 20px;
	
	.list-item {
		background: #ddd;
		margin-bottom: 5px;
		padding: 3px;
	}
}

.customGreeting {
	margin-top: 30px;
	
	.customGreeting-save-btn {
		margin: auto;
		text-align: center;
	}
}
</style>